import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerMessages = () => {
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showNewMessage, setShowNewMessage] = useState(false);
  const [newMessage, setNewMessage] = useState({ subject: '', message: '' });

  useEffect(() => {
    fetchMessages();
  }, []);

  const fetchMessages = async () => {
    try {
      const response = await axios.get(`${API_URL}/messages`);
      setMessages(response.data.data || response.data);
    } catch (error) {
      console.error('Error fetching messages:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_URL}/messages`, newMessage);
      setNewMessage({ subject: '', message: '' });
      setShowNewMessage(false);
      fetchMessages();
    } catch (error) {
      console.error('Error sending message:', error);
    }
  };

  return (
    <div className="main-content">
      <div className="content-container">
        <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <h1>Messages</h1>
            <p>Contact support and view your messages</p>
          </div>
          <button
            onClick={() => setShowNewMessage(!showNewMessage)}
            className="btn-primary"
          >
            {showNewMessage ? 'Cancel' : 'New Message'}
          </button>
        </div>

        {showNewMessage && (
          <div className="card" style={{ marginBottom: '2rem' }}>
            <div className="card-header">
              <h3>Send a Message</h3>
            </div>
            <div className="card-body">
              <form onSubmit={handleSubmit}>
                <div className="form-group">
                  <label className="form-label">Subject</label>
                  <input
                    type="text"
                    value={newMessage.subject}
                    onChange={(e) => setNewMessage({ ...newMessage, subject: e.target.value })}
                    className="form-input"
                    required
                  />
                </div>
                <div className="form-group">
                  <label className="form-label">Message</label>
                  <textarea
                    rows="4"
                    value={newMessage.message}
                    onChange={(e) => setNewMessage({ ...newMessage, message: e.target.value })}
                    className="form-textarea"
                    required
                  />
                </div>
                <button type="submit" className="btn-primary">
                  Send Message
                </button>
              </form>
            </div>
          </div>
        )}

        {loading ? (
          <div className="loading-spinner">Loading...</div>
        ) : messages.length === 0 ? (
          <div className="empty-state">No messages yet</div>
        ) : (
          <div className="messages-list">
            {messages.map((msg) => (
              <div key={msg._id} className="message-card">
                <div className="message-header">
                  <h3>{msg.subject}</h3>
                  <span className={`message-status ${msg.status.toLowerCase()}`}>
                    {msg.status}
                  </span>
                </div>
                <p className="message-content">{msg.message}</p>
                <div className="message-meta">
                  Sent: {new Date(msg.createdAt).toLocaleString()}
                </div>
                {msg.adminReply && (
                  <div className="message-reply">
                    <p><strong>Admin Reply:</strong> {msg.adminReply}</p>
                    <small>{new Date(msg.repliedAt).toLocaleString()}</small>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default CustomerMessages;
